+pub fn community_partition_is_valid(graph: &Graph, communities: &[Vec<String>]) -> bool {
+    let mut seen = HashSet::with_capacity(graph.node_count());
+    for comm in communities {
+        for node in comm {
+            if !graph.has_node(node) || !seen.insert(node.clone()) {
+                return false;
+            }
